    12→
    13→interface TabParseState {
    14→  parsing: boolean;
    15→  parsedSession: ParsedSession | null;
    16→  parseError: string | null;
    17→}
    18→
    19→interface Props {
    20→  tabs: Tab[];
    21→  activeTabId: string;
    22→  onActivateTab: (id: string) => void;
    23→  onCloseTab: (id: string) => void;
    24→  onNewTab: () => void;
    25→  onUpload: (file: File) => Promise<SessionMeta>;
    26→  onUpdateTab: (
    27→    tabId: string,
    28→    updates: Partial<Pick<Tab, 'sessionId' | 'label' | 'filterText'>>
    29→  ) => void;
    30→  getSession: (id: string) => SessionMeta | undefined;
    31→  parseSessionById: (id: string) => Promise<ParsedSession>;
    32→  onGistLoad?: (url: string) => Promise<void>;
    33→  gistLoading?: boolean;
    34→  gistError?: string | null;
    35→  onDelete: (id: string) => void;
    36→  // Local discovery props (local mode only)
    37→  discoverySources?: AgentSource[];
    38→  discoveryLoading?: boolean;
    39→  discoveryError?: string | null;
    40→  discoverySelectedAgent?: string | null;
    41→  onDiscoverySelectAgent?: (agent: string | null) => void;
    42→  onDiscoverySelectSession?: (session: DiscoveredSession) => void;
    43→  onDiscoveryRefresh?: () => void;
    44→}
    45→
    46→let {
    47→  tabs,
    48→  activeTabId,
    49→  onActivateTab,
    50→  onCloseTab,
    51→  onNewTab,
    52→  onUpload,
    53→  onUpdateTab,
    54→  getSession,
    55→  parseSessionById,
    56→  onGistLoad,
    57→  gistLoading = false,
    58→  gistError = null,
    59→  onDelete,
    60→  discoverySources = [],
    61→  discoveryLoading = false,
    62→  discoveryError = null,
    63→  discoverySelectedAgent = null,
    64→  onDiscoverySelectAgent,
    65→  onDiscoverySelectSession,
    66→  onDiscoveryRefresh,
    67→}: Props = $props();
    68→
    69→// Per-tab parsing state — SvelteMap makes .set()/.get()/.delete() reactive
    70→const tabParseStates = new SvelteMap<string, TabParseState>();
    71→
    72→const activeTab = $derived(tabs.find(t => t.id === activeTabId));
    73→const activeSessionId = $derived(activeTab?.sessionId ?? null);
    74→const activeMeta = $derived(
    75→  activeSessionId ? getSession(activeSessionId) : undefined
    76→);
    77→
    78→const activeParseState = $derived<TabParseState>(
    79→  tabParseStates.get(activeTabId) ?? {
    80→    parsing: false,
    81→    parsedSession: null,
    82→    parseError: null,
    83→  }
    84→);
    85→
    86→// Parse session when tab's session changes
    87→$effect(() => {
    88→  const tab = activeTab;
    89→  if (!tab || !tab.sessionId) return;
    90→
    91→  const sessionId = tab.sessionId;
    92→  const existing = tabParseStates.get(tab.id);
    93→
    94→  // Skip if already parsed, parsing, or previously failed
    95→  if (existing?.parsedSession || existing?.parsing || existing?.parseError)
    96→    return;
    97→
    98→  // Start parsing
    99→  tabParseStates.set(tab.id, {
   100→    parsing: true,
   101→    parsedSession: null,
   102→    parseError: null,
   103→  });
   104→
   105→  parseSessionById(sessionId)
   106→    .then(parsed => {
   107→      tabParseStates.set(tab.id, {
   108→        parsing: false,
   109→        parsedSession: parsed,
   110→        parseError: null,
   111→      });
   112→    })
   113→    .catch(err => {
   114→      tabParseStates.set(tab.id, {
   115→        parsing: false,
   116→        parsedSession: null,
   117→        parseError:
   118→          err instanceof Error ? err.message : 'Failed to parse session',
   119→      });
   120→    });
   121→});
   122→
   123→function retryParse() {
   124→  tabParseStates.delete(activeTabId);
   125→}
   126→
   127→async function handleUpload(file: File) {
   128→  const meta = await onUpload(file);
   129→  // Update current tab with the new session
   130→  onUpdateTab(activeTabId, { sessionId: meta.id, label: meta.name });
   131→}
   132→</script>
