   191→      </div>
   192→    {:else if gistLoading && !activeSessionId}
   193→      <div class="flex items-center justify-center h-full">
   194→        <div class="flex flex-col items-center gap-4 text-center">
   195→          <svg
   196→            class="w-8 h-8 text-accent animate-spin"
   197→            viewBox="0 0 24 24"
   198→            fill="none"
   199→          >
   200→            <circle
   201→              class="opacity-25"
   202→              cx="12"
   203→              cy="12"
   204→              r="10"
   205→              stroke="currentColor"
   206→              stroke-width="3"
   207→            ></circle>
   208→            <path
   209→              class="opacity-75"
   210→              fill="currentColor"
   211→              d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
   212→            ></path>
   213→          </svg>
   214→          <div class="space-y-1">
   215→            <p class="text-foreground-bright text-sm font-medium">
   216→              loading session from gist...
