    25→async function handleGistLoad(url: string) {
    26→  const sessions = await sessionState.loadFromGist(url);
    27→  if (sessions.length > 0) {
    28→    // Open first loaded session in current tab
    29→    const first = sessions[0];
    30→    tabState.updateTab(tabState.activeTabId, {
    31→      sessionId: first.id,
    32→      label: first.name,
    33→    });
    34→  }
    35→}
    36→
    37→function handleSelect(id: string) {
    38→  const session = sessionState.getSession(id);
    39→  if (!session) return;
    40→
    41→  // If session is already open in a tab, focus that tab
    42→  const existingTab = tabState.findTabBySessionId(id);
    43→  if (existingTab) {
    44→    tabState.activateTab(existingTab.id);
    45→    return;
    46→  }
    47→
    48→  // Otherwise, open in a new tab
    49→  tabState.openTab(id, session.name);
    50→}
    51→
    52→async function handleSidebarUpload(file: File) {
    53→  const meta = await sessionState.upload(file);
    54→  // Open the uploaded session in a new tab
    55→  tabState.openTab(meta.id, meta.name);
    56→}
    57→
    58→async function handleLocalSessionSelect(session: DiscoveredSession) {
    59→  const filename = basename(session.filePath);
    60→  const content = await fetchSessionContent(session.filePath);
    61→  const meta = await sessionState.storeFromContent(filename, content, {
    62→    type: 'local',
    63→  });
    64→  tabState.openTab(meta.id, meta.name);
    65→}
    66→
    67→function handleDiscover() {
    68→  discoveryState?.discover();
    69→}
    70→
    71→async function handleRemove(id: string) {
    72→  tabState.closeTabsForSession(id);
    73→  await sessionState.remove(id);
    74→}
    75→</script>
