     1→import { parseSession } from '$lib/parsers';
     2→import { fetchGist, isGistError, parseGistUrl } from '$lib/services/gist';
     3→import {
     4→  clearAllSessions,
     5→  initStorage,
     6→  loadManifest,
     7→  readSessionFile,
     8→  removeSession,
     9→  storeSession,
    10→  storeSessionFromContent,
    11→} from '$lib/services/storage.svelte';
    12→import type { SessionMeta } from '$lib/types';
    13→import type { ParsedSession } from '$lib/types/timeline';
    14→
    15→let sessions = $state<SessionMeta[]>([]);
    16→let selectedId = $state<string | null>(null);
    17→let loading = $state(true);
    18→let parsedSession = $state<ParsedSession | null>(null);
    19→let parsing = $state(false);
    20→let parseError = $state<string | null>(null);
    21→let gistLoading = $state(false);
    22→let gistError = $state<string | null>(null);
    23→
    24→const selected = $derived(sessions.find(s => s.id === selectedId));
    25→const count = $derived(sessions.length);
    26→
    27→// Non-reactive cache: sessions are immutable once stored
    28→const parseCache = new Map<string, ParsedSession>();
    29→
    30→function sortSessions() {
    31→  sessions.sort((a, b) => b.uploadedAt - a.uploadedAt);
    32→}
    33→
    34→async function initialize() {
    35→  loading = true;
    36→  try {
    37→    await initStorage();
    38→    sessions = await loadManifest();
    39→    sortSessions();
    40→  } finally {
    41→    loading = false;
    42→  }
    43→}
    44→
    45→async function upload(file: File): Promise<SessionMeta> {
    46→  const meta = await storeSession(file);
    47→  sessions.push(meta);
    48→  sortSessions();
    49→  return meta;
    50→}
    51→
    52→function getSession(id: string): SessionMeta | undefined {
    53→  return sessions.find(s => s.id === id);
    54→}
    55→
    56→async function parseSessionById(id: string): Promise<ParsedSession> {
    57→  // Check cache first
    58→  const cached = parseCache.get(id);
    59→  if (cached) {
    60→    return cached;
    61→  }
    62→
    63→  const meta = sessions.find(s => s.id === id);
    64→  if (!meta) {
    65→    throw new Error('Session not found');
    66→  }
    67→
    68→  const raw = await readSessionFile(meta.id);
    69→  if (!raw) {
    70→    throw new Error('Session file not found');
    71→  }
    72→
    73→  const result = parseSession(raw, meta.format, meta.agentFormat);
    74→  parseCache.set(meta.id, result);
    75→
    76→  // Update agentFormat on meta if not set
    77→  if (!meta.agentFormat) {
    78→    meta.agentFormat = result.format;
    79→  }
    80→
    81→  return result;
    82→}
    83→
    84→async function parseSelected(meta: SessionMeta) {
    85→  // Check cache
    86→  const cached = parseCache.get(meta.id);
    87→  if (cached) {
    88→    parsedSession = cached;
    89→    parseError = null;
    90→    parsing = false;
    91→    return;
    92→  }
    93→
    94→  parsing = true;
    95→  parsedSession = null;
    96→  parseError = null;
    97→
    98→  try {
    99→    const raw = await readSessionFile(meta.id);
   100→    if (!raw) {
   101→      throw new Error('Session file not found');
   102→    }
   103→
   104→    const result = parseSession(raw, meta.format, meta.agentFormat);
   105→    parseCache.set(meta.id, result);
   106→    parsedSession = result;
   107→
   108→    // Update agentFormat on meta if not set
   109→    if (!meta.agentFormat) {
   110→      meta.agentFormat = result.format;
   111→    }
   112→  } catch (err) {
   113→    parseError = err instanceof Error ? err.message : 'Failed to parse session';
   114→    parsedSession = null;
   115→  } finally {
   116→    parsing = false;
   117→  }
   118→}
   119→
   120→async function select(id: string) {
   121→  selectedId = id;
   122→  const meta = sessions.find(s => s.id === id);
   123→  if (meta) {
   124→    await parseSelected(meta);
   125→  }
   126→}
   127→
   128→function deselect() {
   129→  selectedId = null;
   130→  parsedSession = null;
   131→  parseError = null;
   132→}
   133→
   134→async function remove(id: string) {
   135→  await removeSession(id);
   136→  sessions = sessions.filter(s => s.id !== id);
   137→  parseCache.delete(id);
   138→  if (selectedId === id) {
   139→    selectedId = null;
   140→    parsedSession = null;
   141→    parseError = null;
   142→  }
   143→}
   144→
   145→async function clearAll() {
   146→  await clearAllSessions();
   147→  sessions = [];
   148→  selectedId = null;
   149→  parsedSession = null;
   150→  parseError = null;
   151→  parseCache.clear();
   152→}
   153→
   154→async function loadFromGist(gistInput: string): Promise<SessionMeta[]> {
   155→  gistError = null;
   156→  gistLoading = true;
   157→
   158→  try {
   159→    const gistId = parseGistUrl(gistInput);
   160→    if (!gistId) {
   161→      throw { type: 'invalid_url', message: 'Invalid gist URL or ID' };
   162→    }
   163→
   164→    const result = await fetchGist(gistId);
   165→    const loadedSessions: SessionMeta[] = [];
   166→
   167→    for (const file of result.files) {
   168→      const meta = await storeSessionFromContent(file.filename, file.content, {
   169→        type: 'gist',
   170→        gistId: result.metadata.id,
   171→        gistUrl: result.metadata.url,
   172→        owner: result.metadata.owner,
   173→      });
   174→      sessions.push(meta);
   175→      loadedSessions.push(meta);
   176→    }
   177→
   178→    sortSessions();
   179→    return loadedSessions;
   180→  } catch (err) {
   181→    if (isGistError(err)) {
   182→      gistError = err.message;
   183→    } else if (err instanceof Error) {
   184→      gistError = err.message;
   185→    } else {
   186→      gistError = 'Failed to load gist';
   187→    }
   188→    throw err;
   189→  } finally {
   190→    gistLoading = false;
   191→  }
   192→}
   193→
   194→async function storeFromContent(
   195→  filename: string,
   196→  content: string,
   197→  source?: import('$lib/types').SessionSource
   198→): Promise<import('$lib/types').SessionMeta> {
   199→  const meta = await storeSessionFromContent(filename, content, source);
   200→  sessions.push(meta);
   201→  sortSessions();
   202→  return meta;
   203→}
   204→
   205→function setGistLoading(value: boolean) {
   206→  gistLoading = value;
   207→}
   208→
   209→export function getSessionState() {
   210→  return {
   211→    get sessions() {
   212→      return sessions;
   213→    },
   214→    get selectedId() {
   215→      return selectedId;
   216→    },
   217→    get selected() {
   218→      return selected;
   219→    },
   220→    get count() {
   221→      return count;
   222→    },
   223→    get loading() {
   224→      return loading;
   225→    },
   226→    get parsedSession() {
   227→      return parsedSession;
   228→    },
   229→    get parsing() {
   230→      return parsing;
   231→    },
   232→    get parseError() {
   233→      return parseError;
   234→    },
   235→    get gistLoading() {
   236→      return gistLoading;
   237→    },
   238→    get gistError() {
   239→      return gistError;
   240→    },
   241→    initialize,
   242→    upload,
   243→    select,
   244→    deselect,
   245→    remove,
   246→    clearAll,
   247→    getSession,
   248→    parseSessionById,
   249→    loadFromGist,
   250→    storeFromContent,
   251→    setGistLoading,
   252→  };
   253→}
